parameters.text:
=You are an orchestrator for a multi-source news aggregation system.

Request parameters:
- Sources requested: {{ JSON.stringify($json.body.sources || ['hackernews', 'reddit']) }}
- Time range: {{ $json.body.time_range || '24h' }}
- Max stories per source: {{ $json.body.max_stories_per_source || 10 }}
- Categories of interest: {{ JSON.stringify($json.body.categories || ['AI', 'programming', 'startups']) }}

Your task:
1. Plan the aggregation strategy
2. Assign priority to each source based on relevance to categories
3. Define merge criteria for combining stories

Respond with JSON:
{
  "sources": ["source1", "source2"],
  "source_priorities": {"hackernews": 1, "reddit": 2},
  "max_per_source": number,
  "merge_criteria": "title_similarity|url_match|both",
  "category_keywords": ["keyword1", "keyword2"]
}

parameters.jsCode:
// Parse orchestrator response and prepare parallel fetch
const response = $input.first().json;
const webhookInput = $('Webhook Trigger').first().json.body;

let orchestratorData;
try {
  const text = response.output || response.text || response.content || JSON.stringify(response);
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  orchestratorData = jsonMatch ? JSON.parse(jsonMatch[0]) : { sources: ['hackernews', 'reddit'] };
} catch (e) {
  orchestratorData = { sources: ['hackernews', 'reddit'], max_per_source: 10 };
}

return {
  config: orchestratorData,
  webhookInput: webhookInput,
  maxStories: webhookInput?.max_stories_per_source || 10,
  categories: webhookInput?.categories || ['AI', 'programming']
};

// Process HackerNews data - HTTP Request splits array into items
const items = $input.all();
const storyIds = items.map(item => item.json);
const config = $('Parse Orchestrator').first().json;
const maxStories = config.maxStories || 10;

// For simplicity, we'll just use the IDs - in production, fetch each story
const stories = storyIds.slice(0, maxStories).map((id, i) => ({
  id: id,
  source: 'hackernews',
  rank: i + 1,
  url: `https://news.ycombinator.com/item?id=${id}`
}));

return {
  source: 'hackernews',
  stories: stories,
  count: stories.length,
  categories: config.categories
};

// Process Reddit data - handle errors gracefully
const redditData = $input.first().json;
const config = $('Parse Orchestrator').first().json;
const maxStories = config.maxStories || 10;

// Check if we got an error from the HTTP request
if (redditData?.error || !redditData?.data?.children) {
  return {
    source: 'reddit',
    stories: [],
    count: 0,
    error: 'Reddit API unavailable',
    categories: config.categories
  };
}

const posts = redditData.data.children || [];
const stories = posts.slice(0, maxStories).map((post, i) => ({
  id: post.data?.id,
  title: post.data?.title,
  url: post.data?.url,
  score: post.data?.score,
  comments: post.data?.num_comments,
  subreddit: post.data?.subreddit,
  source: 'reddit',
  rank: i + 1,
  permalink: `https://reddit.com${post.data?.permalink}`
}));

return {
  source: 'reddit',
  stories: stories,
  count: stories.length,
  categories: config.categories
};

// Process RSS data
const rssItems = $input.all();
const config = $('Parse Orchestrator').first().json;
const maxStories = config.maxStories || 10;

const stories = rssItems.slice(0, maxStories).map((item, i) => ({
  id: item.json?.guid || `rss-${i}`,
  title: item.json?.title,
  url: item.json?.link,
  description: item.json?.contentSnippet || item.json?.content,
  pubDate: item.json?.pubDate,
  source: 'rss',
  rank: i + 1
}));

return {
  source: 'rss',
  stories: stories,
  count: stories.length,
  categories: config.categories
};

