// Combine all source analyses
const items = $input.all();

const sources = {};
let totalTokens = 0;

for (const item of items) {
  const source = item.json.source;
  sources[source] = {
    analysis: item.json.analysis,
    raw_stories: item.json.raw_stories,
    tokens: item.json.tokens
  };
  totalTokens += item.json.tokens || 0;
}

return {
  sources: sources,
  totalTokens: totalTokens,
  sourceCount: Object.keys(sources).length
};

parameters.text:
=You are a deduplication specialist. Find duplicate or similar stories across these sources.

Sources data:
{{ JSON.stringify($json.sources, null, 2) }}

Identify stories that appear in multiple sources (same topic, different URLs).

Respond with JSON:
{
  "duplicates_found": [
    {
      "topic": "story topic",
      "sources": ["hackernews", "reddit"],
      "story_ids": ["id1", "id2"],
      "recommended_primary": "best_source"
    }
  ],
  "unique_stories_per_source": {
    "hackernews": number,
    "reddit": number,
    "rss": number
  },
  "total_unique_stories": number
}

