// Parse deduplication results
const response = $input.first().json;
const sourcesData = $('Combine Sources').first().json;

let dedupData;
try {
  const text = response.output || response.text || response.content || JSON.stringify(response);
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  dedupData = jsonMatch ? JSON.parse(jsonMatch[0]) : { duplicates_found: [] };
} catch (e) {
  dedupData = { duplicates_found: [], error: e.message };
}

return {
  sources: sourcesData.sources,
  deduplication: dedupData,
  specialistTokens: sourcesData.totalTokens,
  dedupTokens: response.tokenUsage?.totalTokens || 0
};

// Parse synthesis
const response = $input.first().json;
const prevData = $('Parse Deduplication').first().json;

let synthesisData;
try {
  const text = response.output || response.text || response.content || JSON.stringify(response);
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  synthesisData = jsonMatch ? JSON.parse(jsonMatch[0]) : { error: 'parse_failed' };
} catch (e) {
  synthesisData = { error: e.message };
}

return {
  synthesis: synthesisData,
  deduplication: prevData.deduplication,
  specialistTokens: prevData.specialistTokens,
  dedupTokens: prevData.dedupTokens,
  synthesisTokens: response.tokenUsage?.totalTokens || 0
};

// Format final output
const reviewResponse = $input.first().json;
const synthesisData = $('Parse Synthesis').first().json;

let reviewData;
try {
  const text = reviewResponse.output || reviewResponse.text || reviewResponse.content || JSON.stringify(reviewResponse);
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  reviewData = jsonMatch ? JSON.parse(jsonMatch[0]) : { quality_score: 70 };
} catch (e) {
  reviewData = { quality_score: 70, error: e.message };
}

const reviewTokens = reviewResponse.tokenUsage?.totalTokens || 0;
const orchestratorTokens = 200;

return {
  digest: synthesisData.synthesis,
  deduplication_report: synthesisData.deduplication,
  quality_review: reviewData,
  agent_stats: {
    orchestrator_tokens: orchestratorTokens,
    specialist_tokens: synthesisData.specialistTokens,
    deduplicator_tokens: synthesisData.dedupTokens,
    synthesizer_tokens: synthesisData.synthesisTokens,
    reviewer_tokens: reviewTokens,
    total_tokens: orchestratorTokens + synthesisData.specialistTokens + synthesisData.dedupTokens + synthesisData.synthesisTokens + reviewTokens,
    total_agents: 8
  },
  execution_id: $execution.id,
  workflow_id: $workflow.id,
  timestamp: new Date().toISOString()
};

// Placeholder for MAO telemetry - enable when MAO backend is running
// This node is disabled to avoid errors when no MAO instance is available
return $input.first().json;
